#include<bits/stdc++.h>
using namespace std;
int a[5000010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
        }
        vector<pair<int,int>> v;
        long long ans=0;
        for(int i=1;i<=n;i++)
        {
            int j=i;
            while(j<n&&a[j]<a[j+1])
            {
                j++;
            }
            v.push_back({i,j});
            i=j;
        }
        pair<int,int> lst;
        int flag=0;
        for(auto i:v)
        {
            if(flag==0)
            {
                flag=1;
                lst=i;
                continue;
            }
            int l=lst.first,r=lst.second;
            lst=i;
            int j=l;
            for(int k=i.first;k<=i.second;k++)
            {
                while(j<=r&&a[j]<a[k])
                {
                    j++;
                }
                ans+=r-j+1;
            }
        }
        printf("%lld\n",ans);
    }
    return 0;
}
